151: func (p *legacyProvider) NewRESTStorage(apiResourceConfigSource serverstorage.APIResourceConfigSource, restOptionsGetter generic.RESTOptionsGetter) (genericapiserver.APIGroupInfo, error) {
152: 	apiGroupInfo, err := p.GenericConfig.NewRESTStorage(apiResourceConfigSource, restOptionsGetter)
153: 	if err != nil {
154: 		return genericapiserver.APIGroupInfo{}, err
155: 	}
156: 
157: 	podDisruptionClient, err := policyclient.NewForConfig(p.LoopbackClientConfig)
158: 	if err != nil {
159: 		return genericapiserver.APIGroupInfo{}, err
160: 	}
161: 
162: 	podTemplateStorage, err := podtemplatestore.NewREST(restOptionsGetter)
163: 	if err != nil {
164: 		return genericapiserver.APIGroupInfo{}, err
165: 	}
166: 
167: 	limitRangeStorage, err := limitrangestore.NewREST(restOptionsGetter)
168: 	if err != nil {
169: 		return genericapiserver.APIGroupInfo{}, err
170: 	}
171: 
172: 	persistentVolumeStorage, persistentVolumeStatusStorage, err := pvstore.NewREST(restOptionsGetter)
173: 	if err != nil {
174: 		return genericapiserver.APIGroupInfo{}, err
175: 	}
176: 	persistentVolumeClaimStorage, persistentVolumeClaimStatusStorage, err := pvcstore.NewREST(restOptionsGetter)
177: 	if err != nil {
178: 		return genericapiserver.APIGroupInfo{}, err
179: 	}
180: 
181: 	endpointsStorage, err := endpointsstore.NewREST(restOptionsGetter)
182: 	if err != nil {
183: 		return genericapiserver.APIGroupInfo{}, err
184: 	}
185: 
186: 	nodeStorage, err := nodestore.NewStorage(restOptionsGetter, p.Proxy.KubeletClientConfig, p.Proxy.Transport)
187: 	if err != nil {
188: 		return genericapiserver.APIGroupInfo{}, err
189: 	}
190: 
191: 	podStorage, err := podstore.NewStorage(
192: 		restOptionsGetter,
193: 		nodeStorage.KubeletConnectionInfo,
194: 		p.Proxy.Transport,
195: 		podDisruptionClient,
196: 	)
197: 	if err != nil {
198: 		return genericapiserver.APIGroupInfo{}, err
199: 	}
200: 
201: 	serviceRESTStorage, serviceStatusStorage, serviceRESTProxy, err := servicestore.NewREST(
202: 		restOptionsGetter,
203: 		p.primaryServiceClusterIPAllocator.IPFamily(),
204: 		p.serviceClusterIPAllocators,
205: 		p.serviceNodePortAllocator,
206: 		endpointsStorage,
207: 		podStorage.Pod,
208: 		p.Proxy.Transport)
209: 	if err != nil {
210: 		return genericapiserver.APIGroupInfo{}, err
211: 	}
212: 
213: 	storage := apiGroupInfo.VersionedResourcesStorageMap["v1"]
214: 	if storage == nil {
215: 		storage = map[string]rest.Storage{}
216: 	}
217: 
218: 	// potentially override the generic serviceaccount storage with one that supports pods
219: 	var serviceAccountStorage *serviceaccountstore.REST
220: 	if p.ServiceAccountIssuer != nil {
221: 		var nodeGetter rest.Getter
222: 		if utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenNodeBinding) ||
223: 			utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenPodNodeInfo) {
224: 			nodeGetter = nodeStorage.Node.Store
225: 		}
226: 		serviceAccountStorage, err = serviceaccountstore.NewREST(restOptionsGetter, p.ServiceAccountIssuer, p.APIAudiences, p.ServiceAccountMaxExpiration, podStorage.Pod.Store, storage["secrets"].(rest.Getter), nodeGetter, p.ExtendExpiration, p.IsTokenSignerExternal)
227: 		if err != nil {
228: 			return genericapiserver.APIGroupInfo{}, err
229: 		}
230: 	}
231: 
232: 	if resource := "pods"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
233: 		storage[resource] = podStorage.Pod
234: 		storage[resource+"/attach"] = podStorage.Attach
235: 		storage[resource+"/status"] = podStorage.Status
236: 		storage[resource+"/log"] = podStorage.Log
237: 		storage[resource+"/exec"] = podStorage.Exec
238: 		storage[resource+"/portforward"] = podStorage.PortForward
239: 		storage[resource+"/proxy"] = podStorage.Proxy
240: 		storage[resource+"/binding"] = podStorage.Binding
241: 		if podStorage.Eviction != nil {
242: 			storage[resource+"/eviction"] = podStorage.Eviction
243: 		}
244: 		storage[resource+"/ephemeralcontainers"] = podStorage.EphemeralContainers
245: 		if utilfeature.DefaultFeatureGate.Enabled(features.InPlacePodVerticalScaling) {
246: 			storage[resource+"/resize"] = podStorage.Resize
247: 		}
248: 	}
249: 	if resource := "bindings"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
250: 		storage[resource] = podStorage.LegacyBinding
251: 	}
252: 
253: 	if resource := "podtemplates"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
254: 		storage[resource] = podTemplateStorage
255: 	}
256: 
257: 	if resource := "replicationcontrollers"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
258: 		controllerStorage, err := controllerstore.NewStorage(restOptionsGetter)
259: 		if err != nil {
260: 			return genericapiserver.APIGroupInfo{}, err
261: 		}
262: 
263: 		storage[resource] = controllerStorage.Controller
264: 		storage[resource+"/status"] = controllerStorage.Status
265: 		if legacyscheme.Scheme.IsVersionRegistered(schema.GroupVersion{Group: "autoscaling", Version: "v1"}) {
266: 			storage[resource+"/scale"] = controllerStorage.Scale
267: 		}
268: 	}
269: 
270: 	// potentially override generic storage for service account (with pod support)
271: 	if resource := "serviceaccounts"; serviceAccountStorage != nil && apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
272: 		// don't leak go routines
273: 		storage[resource].Destroy()
274: 		if storage[resource+"/token"] != nil {
275: 			storage[resource+"/token"].Destroy()
276: 		}
277: 
278: 		storage[resource] = serviceAccountStorage
279: 		if serviceAccountStorage.Token != nil {
280: 			storage[resource+"/token"] = serviceAccountStorage.Token
281: 		}
282: 	}
283: 
284: 	if resource := "services"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
285: 		storage[resource] = serviceRESTStorage
286: 		storage[resource+"/proxy"] = serviceRESTProxy
287: 		storage[resource+"/status"] = serviceStatusStorage
288: 	}
289: 
290: 	if resource := "endpoints"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
291: 		storage[resource] = endpointsStorage
292: 	}
293: 
294: 	if resource := "nodes"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
295: 		storage[resource] = nodeStorage.Node
296: 		storage[resource+"/proxy"] = nodeStorage.Proxy
297: 		storage[resource+"/status"] = nodeStorage.Status
298: 	}
299: 
300: 	if resource := "limitranges"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
301: 		storage[resource] = limitRangeStorage
302: 	}
303: 
304: 	if resource := "persistentvolumes"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
305: 		storage[resource] = persistentVolumeStorage
306: 		storage[resource+"/status"] = persistentVolumeStatusStorage
307: 	}
308: 
309: 	if resource := "persistentvolumeclaims"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
310: 		storage[resource] = persistentVolumeClaimStorage
311: 		storage[resource+"/status"] = persistentVolumeClaimStatusStorage
312: 	}
313: 
314: 	if resource := "componentstatuses"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
315: 		storage[resource] = componentstatus.NewStorage(componentStatusStorage{p.StorageFactory}.serversToValidate)
316: 	}
317: 
318: 	if len(storage) > 0 {
319: 		apiGroupInfo.VersionedResourcesStorageMap["v1"] = storage
320: 	}
321: 
322: 	return apiGroupInfo, nil
323: }
